from itertools import combinations

basket = transactions.groupby('Customer')['Product'].apply(list)
pairs = {}
for items in basket:
    for a, b in combinations(sorted(set(items)), 2):
        pairs[(a, b)] = pairs.get((a, b), 0) + 1

print('Frequent co-purchase pairs:')
for k, v in sorted(pairs.items(), key=lambda x: -x[1]):
    print(f'  {k[0]} + {k[1]}: {v} customers')

import pandas as pd

df = pd.DataFrame({
    'House':   ['H1','H2','H3','H4','H5','H6'],
    'Size_m2': [50, 55, 48, 120, 130, 125],
    'Price_B': [1.2, 1.3, 1.1, 3.5, 3.8, 3.6]
})
df['Cluster'] = df['Size_m2'].apply(
    lambda x: 'Small (<80m2)' if x < 80 else 'Large (>100m2)'
)
print(df[['House','Size_m2','Price_B','Cluster']].to_string(index=False))
print()
for c, g in df.groupby('Cluster'):
    print(f'{c}: avg price = {g["Price_B"].mean():.2f} billion')
